import{_ as a,o as c,c as o,a0 as t}from"./chunks/framework.DgPozsi0.js";const p=JSON.parse('{"title":"[React官網] React 19.2 教程","description":"","frontmatter":{"title":"[React官網] React 19.2 教程","outline":2},"headers":[],"relativePath":"pages/f2e/docReact/reactDev/reactDev_08.md","filePath":"pages/f2e/docReact/reactDev/reactDev_08.md"}'),d={name:"pages/f2e/docReact/reactDev/reactDev_08.md"};function i(l,e,r,f,s,h){return c(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="脫圍機制-escape-hatches" tabindex="-1">脫圍機制（Escape Hatches） <a class="header-anchor" href="#脫圍機制-escape-hatches" aria-label="Permalink to &quot;脫圍機制（Escape Hatches）&quot;">​</a></h1><p>有些組件可能需要控制和同步 <code>React</code> 之外的系統。例如，你可能需要使用瀏覽器 <code>API</code> 聚焦輸入框，或者在沒有 <code>React</code> 的情況下實現影片播放器，或者連接並監聽遠端伺服器的消息。在本章中，你將學習到一些脫圍機制，讓你可以“走出” <code>React</code> 並連接到外部系統。大多數應用邏輯和數據流不應該依賴這些功能。</p><div class="info custom-block"><p class="custom-block-title">你將學到</p><ul><li><a href="/vitepress-study/pages/f2e/docReact/reactDev/08/reactDev_08_01.html">在不重新渲染的情況下“記住”資訊</a></li><li><a href="/vitepress-study/pages/f2e/docReact/reactDev/08/reactDev_08_02.html">訪問 React 管理的 DOM 元素</a></li><li><a href="/vitepress-study/pages/f2e/docReact/reactDev/08/reactDev_08_03.html">將組件與外部系統同步</a></li><li><a href="/vitepress-study/pages/f2e/docReact/reactDev/08/reactDev_08_04.html">從組件中刪除不必要的 Effect</a></li><li><a href="/vitepress-study/pages/f2e/docReact/reactDev/08/reactDev_08_05.html">Effect 的生命週期與組件的生命週期有何不同</a></li><li><a href="/vitepress-study/pages/f2e/docReact/reactDev/08/reactDev_08_06.html">防止某些值重新觸發 Effect</a></li><li><a href="/vitepress-study/pages/f2e/docReact/reactDev/08/reactDev_08_07.html">減少 Effect 重新執行的頻率</a></li><li><a href="/vitepress-study/pages/f2e/docReact/reactDev/08/reactDev_08_08.html">在組件之間共享邏輯</a></li></ul></div><h2 id="使用-ref-引用值" tabindex="-1">使用 ref 引用值 <a class="header-anchor" href="#使用-ref-引用值" aria-label="Permalink to &quot;使用 ref 引用值&quot;">​</a></h2><ul><li><p>當你希望組件 <code>“記住”</code> 某些資訊，但又不想讓這些資訊觸發新的渲染時，可以使用 <code>ref</code>。例如：</p><div class="language-jsx vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ref</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> useRef</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><h4 id="與-state-的異同" tabindex="-1">與 state 的異同 <a class="header-anchor" href="#與-state-的異同" aria-label="Permalink to &quot;與 state 的異同&quot;">​</a></h4><ul><li><code>ref</code> 與 <code>state</code> 一樣，在重新渲染之間都會由 <code>React</code> 保留。</li><li>但是，設定 <code>state</code> 會重新渲染組件，而變更 <code>ref</code> 則不會。</li></ul></li><li><h4 id="訪問方式" tabindex="-1">訪問方式 <a class="header-anchor" href="#訪問方式" aria-label="Permalink to &quot;訪問方式&quot;">​</a></h4><p>透過 <code>ref.current</code> 屬性可以訪問該 <code>ref</code> 的當前值。</p></li><li><h4 id="應用場景" tabindex="-1">應用場景 <a class="header-anchor" href="#應用場景" aria-label="Permalink to &quot;應用場景&quot;">​</a></h4><p><code>ref</code> 就像組件一個不被 <code>React</code> 追蹤的秘密口袋。可用於存儲 <code>timeout ID</code>、<code>DOM 元素</code> 和其他不影響組件渲染輸出（UI）的物件。</p></li></ul><h2 id="使用-ref-操作-dom" tabindex="-1">使用 ref 操作 DOM <a class="header-anchor" href="#使用-ref-操作-dom" aria-label="Permalink to &quot;使用 ref 操作 DOM&quot;">​</a></h2><ul><li><p>由於 <code>React</code> 會自動更新 <code>DOM</code> 以匹配渲染輸出，因此組件通常不需要操作 <code>DOM</code>。但有時需要訪問由 <code>React</code> 管理的 <code>DOM</code> 元素（例如：聚焦節點、捲動到此節點、測量其尺寸和位置）。</p></li><li><h4 id="實現方式" tabindex="-1">實現方式 <a class="header-anchor" href="#實現方式" aria-label="Permalink to &quot;實現方式&quot;">​</a></h4><p><code>React</code> 沒有內置方法來執行此類操作，因此需要一個指向 <code>DOM</code> 節點的 <code>ref</code>。例如，在 <code>&lt;input ref={inputRef} /&gt;</code> 綁定後，點擊按鈕時調用 <code>inputRef.current.focus()</code> 即可聚焦輸入框。</p></li></ul><h2 id="使用-effect-進行同步" tabindex="-1">使用 Effect 進行同步 <a class="header-anchor" href="#使用-effect-進行同步" aria-label="Permalink to &quot;使用 Effect 進行同步&quot;">​</a></h2><ul><li><p>有些組件需要與外部系統同步（例如：根據 <code>React</code> 狀態控制非 <code>React</code> 組件、設置伺服器連接、在組件出現在螢幕上時發送分析日誌）。</p></li><li><h4 id="與事件處理函數的區別" tabindex="-1">與事件處理函數的區別 <a class="header-anchor" href="#與事件處理函數的區別" aria-label="Permalink to &quot;與事件處理函數的區別&quot;">​</a></h4><p>事件處理函數只處理特定的用戶交互事件；而 <code>Effect</code> 則是在渲染後運行一些代碼。</p></li><li><h4 id="清理函數-cleanup" tabindex="-1">清理函數（Cleanup） <a class="header-anchor" href="#清理函數-cleanup" aria-label="Permalink to &quot;清理函數（Cleanup）&quot;">​</a></h4><p>許多 <code>Effect</code> 需要自行 <code>“清理”</code>。例如聊天伺服器連接的 <code>Effect</code> 應該返回一個 <code>cleanup</code> 函數，告訴 <code>React</code> 如何斷開連接，以確保沒有內存洩漏。</p></li><li><h4 id="開發環境行為" tabindex="-1">開發環境行為 <a class="header-anchor" href="#開發環境行為" aria-label="Permalink to &quot;開發環境行為&quot;">​</a></h4><p>在開發環境中，<code>React</code> 會立即運行並額外清理一次 <code>Effect</code>（印出兩次連接資訊），這是為了確保開發者沒有忘記實現清理功能。</p></li></ul><h2 id="你可能不需要-effect" tabindex="-1">你可能不需要 Effect <a class="header-anchor" href="#你可能不需要-effect" aria-label="Permalink to &quot;你可能不需要 Effect&quot;">​</a></h2><ul><li><p><code>Effect</code> 是 <code>React</code> 範式中的一種脫圍機制，用於與外部系統同步。如果沒有涉及到外部系統（例如：單純想根據 <code>props</code> 或 <code>state</code> 的變化來更新另一個 <code>state</code>），則不應該使用 <code>Effect</code>。移除不必要的 <code>Effect</code> 可以讓代碼更容易理解、運行更快且更少出錯。</p></li><li><p>常見的不必使用 <code>Effect</code> 的情況包括：</p><ul><li>不必為了渲染而使用 <code>Effect</code> 來轉換數據：例如不需要用 <code>Effect</code> 監聽 <code>firstName</code> 和 <code>lastName</code> 來更新 <code>fullName</code> 狀態，直接在渲染期間進行計算即可（<code>const fullName = firstName + &#39; &#39; + lastName;</code>）。</li><li>不必使用 <code>Effect</code> 來處理用戶事件。</li></ul></li></ul><h2 id="響應式-effect-的生命週期" tabindex="-1">響應式 Effect 的生命週期 <a class="header-anchor" href="#響應式-effect-的生命週期" aria-label="Permalink to &quot;響應式 Effect 的生命週期&quot;">​</a></h2><ul><li><p><code>Effect</code> 的生命週期不同於組件。組件可以掛載、更新或卸載。但 <code>Effect</code> 只能做兩件事：開始同步某些東西，然後停止同步它。</p></li><li><h4 id="重新同步機制" tabindex="-1">重新同步機制 <a class="header-anchor" href="#重新同步機制" aria-label="Permalink to &quot;重新同步機制&quot;">​</a></h4><p>如果 <code>Effect</code> 依賴於隨時間變化的 <code>props</code> 和 <code>state</code>（這些是響應值），當這些值在重新渲染時發生改變，<code>Effect</code> 就會重新同步（例如 <code>roomId</code> 改變時，<code>Effect</code> 會先斷開舊連接並建立新連接）。</p></li><li><h4 id="檢查工具規則" tabindex="-1">檢查工具規則 <a class="header-anchor" href="#檢查工具規則" aria-label="Permalink to &quot;檢查工具規則&quot;">​</a></h4><p><code>React</code> 提供了代碼檢查工具，會自動驗證是否正確地將 <code>Effect</code> 中讀取的所有響應式值指定在依賴項列表中。</p></li></ul><h2 id="將事件從-effect-中分開" tabindex="-1">將事件從 Effect 中分開 <a class="header-anchor" href="#將事件從-effect-中分開" aria-label="Permalink to &quot;將事件從 Effect 中分開&quot;">​</a></h2><ul><li><h4 id="問題所在" tabindex="-1">問題所在 <a class="header-anchor" href="#問題所在" aria-label="Permalink to &quot;問題所在&quot;">​</a></h4><p><code>Effect</code> 中的所有代碼都是響應式的。如果 <code>Effect</code> 讀取了多個響應式的值（例如 <code>roomId</code> 和 <code>theme</code>），當其中任一值改變時 <code>Effect</code> 都會重新運行。但有時我們只希望 <code>Effect</code> 響應某些值的變化（如 <code>roomId</code>），而不希望其他值（如 <code>theme</code> 變更）導致 <code>Effect</code> 重新連接。</p></li><li><h4 id="解決方案-effect-event" tabindex="-1">解決方案（Effect Event） <a class="header-anchor" href="#解決方案-effect-event" aria-label="Permalink to &quot;解決方案（Effect Event）&quot;">​</a></h4><p>可以將讀取 <code>theme</code> 這種不需要觸發重新同步的代碼，從 <code>Effect</code> 移到 <code>Effect Event</code>（使用 <code>useEffectEvent</code>）當中。<code>Effect Event</code> 中的代碼不是響應式的，因此更改該值不會導致 <code>Effect</code> 重新執行。</p></li></ul><h2 id="移除-effect-依賴" tabindex="-1">移除 Effect 依賴 <a class="header-anchor" href="#移除-effect-依賴" aria-label="Permalink to &quot;移除 Effect 依賴&quot;">​</a></h2><ul><li><p>代碼檢查器會驗證 <code>Effect</code> 讀取的每一個響應式值是否都包含在依賴列表中，以確保同步。但不必要的依賴關係會導致 <code>Effect</code> 運行過於頻繁，甚至產生無限循環。</p></li><li><h4 id="正確的調整方式" tabindex="-1">正確的調整方式 <a class="header-anchor" href="#正確的調整方式" aria-label="Permalink to &quot;正確的調整方式&quot;">​</a></h4><p>不能直接在依賴列表中強行刪除依賴項。相反地，應該更改周圍的代碼，使該依賴關係變得不必要。</p></li><li><h4 id="範例" tabindex="-1">範例 <a class="header-anchor" href="#範例" aria-label="Permalink to &quot;範例&quot;">​</a></h4><p>如果 <code>Effect</code> 依賴一個在組件內每次渲染都會重新建立的 <code>options</code> 物件，這會導致每次輸入都會重新連接。解決方法是將 <code>options</code> 物件的建立過程直接移到 <code>Effect</code> 內部，這樣 <code>Effect</code> 就只需要依賴 <code>roomId</code> 字串，從而使物件依賴變得不必要。</p></li><li><p>依賴列表是 <code>Effect</code> 代碼所使用之所有響應值的客觀描述，要改變依賴列表，必須先改變代碼邏輯。</p></li></ul><h2 id="使用自定義-hook-複用邏輯" tabindex="-1">使用自定義 Hook 複用邏輯 <a class="header-anchor" href="#使用自定義-hook-複用邏輯" aria-label="Permalink to &quot;使用自定義 Hook 複用邏輯&quot;">​</a></h2><ul><li><p>除了 <code>React</code> 內置的 <code>Hook</code>（如 <code>useState</code>, <code>useEffect</code>），開發者可以根據應用需求創建自己的自定義 <code>Hook</code>，例如用於獲取數據、記錄用戶是否在線或連接聊天室。</p></li><li><h4 id="封裝與組合" tabindex="-1">封裝與組合 <a class="header-anchor" href="#封裝與組合" aria-label="Permalink to &quot;封裝與組合&quot;">​</a></h4><p>可以創建自定義 <code>Hook</code>（如 <code>usePointerPosition</code> 追蹤指針、<code>useDelayedValue</code> 讓值滯後），並在組件之間重用它們。</p></li><li><h4 id="長遠優勢" tabindex="-1">長遠優勢 <a class="header-anchor" href="#長遠優勢" aria-label="Permalink to &quot;長遠優勢&quot;">​</a></h4><p>隨著應用程式規模擴大，藉由重用已編寫好的自定義 <code>Hook</code>，或者使用 <code>React</code> 社群維護的優秀自定義 <code>Hook</code>，開發者手動編寫 <code>Effect</code> 的次數將會逐漸減少。</p></li></ul>',19)])])}const u=a(d,[["render",i]]);export{p as __pageData,u as default};
